solution_code:
#include <iostream>

namespace doubler
{
    int compute(int n) { return n * 2; }
}

namespace tripler
{
    int compute(int n) { return n * 3; }
}

int main()
{
    int n;
    std::cin >> n;
    std::cout << "Double: " << doubler::compute(n) << "\n";
    std::cout << "Triple: " << tripler::compute(n) << "\n";
    return 0;
}

